const CLASS_NAMES: [&str; 5] = ["absent", "present_still", "present_moving", "active", "lying_still"];

/// Classify a 28-feature vector. Returns (class_index, confidence, class_name).
pub fn classify(features: &[f32; 28]) -> (usize, f32, &'static str) {
    // Normalize
    let mut x = [0.0f32; 28];
    for i in 0..28 {
        x[i] = (features[i] - NORM_MEAN[i]) / NORM_STD[i];
    }

    // Layer 0: 28 -> 128 (ReLU)
    let mut h0 = [0.0f32; 128];
    for j in 0..128 {
        let mut sum = B0[j];
        for i in 0..28 { sum += x[i] * W0[i][j]; }
        h0[j] = if sum > 0.0 { sum } else { 0.0 };
    }

    // Layer 1: 128 -> 64 (ReLU)
    let mut h1 = [0.0f32; 64];
    for j in 0..64 {
        let mut sum = B1[j];
        for i in 0..128 { sum += h0[i] * W1[i][j]; }
        h1[j] = if sum > 0.0 { sum } else { 0.0 };
    }

    // Layer 2: 64 -> 32 (ReLU)
    let mut h2 = [0.0f32; 32];
    for j in 0..32 {
        let mut sum = B2[j];
        for i in 0..64 { sum += h1[i] * W2[i][j]; }
        h2[j] = if sum > 0.0 { sum } else { 0.0 };
    }

    // Layer 3: 32 -> 5 (softmax)
    let mut logits = [0.0f32; 5];
    for j in 0..5 {
        let mut sum = B3[j];
        for i in 0..32 { sum += h2[i] * W3[i][j]; }
        logits[j] = sum;
    }

    // Softmax
    let max_l = logits.iter().cloned().fold(f32::NEG_INFINITY, f32::max);
    let mut exp_sum = 0.0f32;
    let mut probs = [0.0f32; 5];
    for j in 0..5 {
        probs[j] = (logits[j] - max_l).exp();
        exp_sum += probs[j];
    }
    for j in 0..5 { probs[j] /= exp_sum; }

    let mut best = 0;
    for j in 1..5 {
        if probs[j] > probs[best] { best = j; }
    }
    (best, probs[best], CLASS_NAMES[best])
}
